// Solution
function insert(word) {
  let node = root;
  for (let char of word) {
    if (!node[char]) {
      node[char] = {};
    }
    node = node[char];
  }
  // Update the node with the new word, and also update the parent nodes correctly
  while (node.parent) {
    node.parent[word.charCodeAt(word.length - 1)] = node;
    node = node.parent;
  }
  return root;
}
